var b = createSprite(200, 200);
b.setAnimation("download (3).jpg_1");
var bullet = createSprite(200000000000000, 200);
bullet.setAnimation("ammo");
var tank = createSprite(380, 380);
tank.setAnimation("Tank1");
var t = createSprite(20, 20);
t.setAnimation("tank2");
var boi = createSprite(200000000000, 200);
boi.setAnimation("bu");
var one = createSprite(200, 200);
one.setAnimation("png_1");
var two = createSprite(200, 200);
two.setAnimation("png_2");
var three = createSprite(200, 200);
three.setAnimation("png_3");
b.scale = 2.5;
tank.scale = 0.25;
t.scale = 0.25;
bullet.scale = 0.25;
boi.scale = 0.25;
//l
var playerone = 100;
var playertwo = 100;
var a = createSprite(200, 200);
a.setAnimation("animation_1");
var ga = createSprite(200, 200);
ga.setAnimation("download");
var ww = createSprite(200, 200);
ww.setAnimation("download (7).jpg_1");
var m = createSprite(200, 330);
m.setAnimation("an");
three.scale = 0.2;
two.scale = 0.2;
one.scale = 0.2;
a.scale = 20;
ga.visible = 0;
ww.visible = 1;
m.visible = 0;
//l
one.x = randomNumber(10, 390);
two.x = randomNumber(10, 390);
three.x = randomNumber(10, 390);
one.y = randomNumber(10, 390);
two.y = randomNumber(10, 390);
three.y = randomNumber(10, 390);
function draw() {
  boi.collide(one);
  boi.collide(two);
  boi.collide(three);
  bullet.collide(one);
  bullet.collide(two);
  bullet.collide(three);
  t.bounceOff(one);
  t.bounceOff(two);
  t.bounceOff(three);
  tank.bounceOff(one);
  tank.bounceOff(two);
  tank.bounceOff(three);
  if (bullet.isTouching(t)) {
    playerone = playerone - 10;
    bullet.x = -100000;
  }
  if (boi.isTouching(tank)) {
    playertwo = playertwo - 10;
    boi.x = -10000000000000;
  }
  if (keyWentDown("l")) {
      bullet.x = tank.x;
      bullet.y = tank.y;
      bullet.scale = 0.25;
      bullet.setSpeed(8, tank.rotation);
      bullet.rotation += 0;
    }
  if (keyDown("up")) {
    tank.y = tank.y - 3.5;
    bullet.rotation = 270;
    tank.rotation = 270;
  }
  if (keyDown("right")) {
    tank.x = tank.x + 3.5;
    tank.rotation = 0;
    bullet.rotation = 0;
  }
  if (keyDown("left")) {
    tank.x = tank.x - 3.5;
    tank.rotation = 180;
    bullet.rotation = 180;
  }
  // update sprites
  if (keyDown("down")) {
    tank.y = tank.y + 3.5;
    tank.rotation = 90;
    bullet.rotation = 90;
  }
  if (keyWentDown("r")) {
      boi.x = t.x;
      boi.y = t.y;
      boi.scale = 0.25;
      boi.setSpeed(-8, t.rotation);
    }
  if (keyDown("w")) {
    t.y = t.y - 3.5;
    boi.rotation = 270;
    t.rotation = 90;
  }
  if (keyDown("d")) {
    t.x = t.x + 3.5;
    t.rotation = 180;
    boi.rotation = 0;
  }
  if (keyDown("a")) {
    t.x = t.x - 3.5;
    t.rotation = 0;
    boi.rotation = 180;
  }
  // update sprites
  if (keyDown("s")) {
    t.y = t.y + 3.5;
    t.rotation = 270;
    boi.rotation = 90;
  }
  if (playerone == 0) {
    GameOver();
  }
  if (playertwo == 0) {
    GameOver();
  }
  if (keyWentDown("space")) {
    Go();
  }
  if (keyWentDown("1")) {
    reset();
    m.visible = 0;
  }
  drawSprites();
  textSize(14);
  stroke("white");
  text("playerone", 20, 15);
  text("playertwo", 280, 15);
  text(playerone, 100, 15);
  text(playertwo, 350, 15);
}
function reset() {
  playerone = 100;
  playertwo = 100;
  a.visible = 0;
  ga.visible = 0;
  tank.x = 20;
  tank.y = 20;
  t.x = 380;
  t.y = 380;
}
function GameOver() {
  a.visible = 1;
  a.scale = 20;
  ga.visible = 1;
  m.visible = 1;
}
function Go() {
  ww.visible = 0;
  a.visible = 0;
}

// Create your functions here
